import React from 'react';
import { topBoxCards } from '../../constants/data';
import { Box, Grid, Typography } from '@mui/material';

function Skills() {
  return (
      <Grid container spacing={5} sx={{ pb: 0, justifyContent: 'space-between' }}>
          {topBoxCards.map((cards, i) => (
              <Grid item xs={12} sm={4} lg={4} md={4} key={i}>
                  <Box className="top-boxes animate__animated animate__fadeInDown animate__delay-1s">
                      <Box sx={{ mb: 2 }}>
                          <Typography variant="h3">{cards.BoxImg()}</Typography>
                      </Box>
                      <Box
                          sx={{
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'space-between',
                          }}
                      >
                          <Box className="flex-fill">
                              <Typography variant="h4" className="h4Active">
                                  {cards.name}
                              </Typography>
                          </Box>
                          <Box>
                              <svg
                                  xmlns="http://www.w3.org/2000/svg"
                                  width="36"
                                  height="36"
                                  fill="#1A2733"
                                  className="bi bi-arrow-right-circle h4Active"
                                  viewBox="0 0 16 16"
                              >
                                  <path
                                      fillRule="evenodd"
                                      d="M1 8a7 7 0 1 0 14 0A7 7 0 0 0 1 8zm15 0A8 8 0 1 1 0 8a8 8 0 0 1 16 0zM4.5 7.5a.5.5 0 0 0 0 1h5.793l-2.147 2.146a.5.5 0 0 0 .708.708l3-3a.5.5 0 0 0 0-.708l-3-3a.5.5 0 1 0-.708.708L10.293 7.5H4.5z"
                                  />
                              </svg>
                          </Box>
                      </Box>
                  </Box>
              </Grid>
          ))}
      </Grid>
  )
}

export default Skills